import re

def extract_final_answer(text: str) -> str:
    """Extract the last line that looks like a standalone answer."""
    lines = [l.strip() for l in text.strip().split("\n") if l.strip()]
    # Prefer a line starting with "Answer:" or "Final answer:"
    for line in reversed(lines):
        if re.match(r'^(answer|final answer|result)[:\s]', line, re.I):
            return re.sub(r'^(answer|final answer|result)[:\s]+', '', line, flags=re.I).strip()
    return lines[-1] if lines else ""

def normalise_numeric(text: str) -> str:
    """Strip units, commas, currency symbols and normalise to a bare number."""
    answer = extract_final_answer(text)
    # Remove currency symbols, commas, trailing punctuation
    cleaned = re.sub(r'[,$€£%()]', '', answer).strip().rstrip('.')
    # Normalise decimals: 391.0 → 391
    try:
        return str(int(float(cleaned)))
    except ValueError:
        return cleaned.lower()

def majority_vote_numeric(prompt: str, n: int = 5) -> tuple[str, Counter]:
    with ThreadPoolExecutor(max_workers=n) as pool:
        raw_samples = list(pool.map(lambda _: sample_once(prompt), range(n)))

    normalised = [normalise_numeric(s) for s in raw_samples]
    counts = Counter(normalised)
    winner = counts.most_common(1)[0][0]
    return winner, counts

winner, counts = majority_vote_numeric(
    "A store sells 17 boxes of 23 items each. How many items total?", n=7
)
print(f"Winner: {winner}  Counts: {dict(counts)}")

from dataclasses import dataclass

@dataclass
class ScoredSample:
    answer: str
    score: float   # 0.0–1.0, higher = more confident

def verifier_score(prompt: str, answer: str) -> float:
    """Ask the model to rate its own answer (0–10). Returns 0.0–1.0."""
    rating_prompt = (
        f"Original question: {prompt}\n"
        f"Proposed answer: {answer}\n\n"
        "Rate the correctness of this answer from 0 to 10. "
        "Reply with ONLY a number."
    )
    raw = sample_once(rating_prompt, temperature=0.0)
    try:
        return min(max(float(raw.strip()) / 10.0, 0.0), 1.0)
    except ValueError:
        return 0.5

def weighted_majority_vote(prompt: str, n: int = 5) -> str:
    with ThreadPoolExecutor(max_workers=n) as pool:
        raw_samples = list(pool.map(lambda _: sample_once(prompt), range(n)))

    # Score each sample (in parallel to keep latency low)
    with ThreadPoolExecutor(max_workers=n) as pool:
        scores = list(pool.map(lambda s: verifier_score(prompt, s), raw_samples))

    scored = [ScoredSample(normalise_numeric(s), sc)
              for s, sc in zip(raw_samples, scores)]

    # Accumulate weighted votes
    weighted: dict[str, float] = {}
    for sample in scored:
        weighted[sample.answer] = weighted.get(sample.answer, 0.0) + sample.score

    return max(weighted, key=weighted.__getitem__)

VOTING_TEMPLATE = """Solve the following problem step by step.
Show all working in your reasoning.
On the very last line, write ONLY: Answer: <value>

Problem: {problem}
"""

def structured_majority_vote(problem: str, n: int = 5) -> str:
    prompt = VOTING_TEMPLATE.format(problem=problem)
    with ThreadPoolExecutor(max_workers=n) as pool:
        samples = list(pool.map(lambda _: sample_once(prompt, temperature=0.8), range(n)))

    def extract_structured(text: str) -> str:
        for line in reversed(text.strip().split("\n")):
            m = re.match(r'^answer:\s*(.+)$', line.strip(), re.I)
            if m:
                return m.group(1).strip().lower()
        return ""  # failed extraction

    answers = [extract_structured(s) for s in samples]
    answers = [a for a in answers if a]  # filter failed extractions
    if not answers:
        return samples[0]  # fallback: return first raw sample

    counts = Counter(answers)
    return counts.most_common(1)[0][0]

result = structured_majority_vote(
    "A train travels 120 km in 1.5 hours. What is its speed in km/h?", n=5
)
print(f"Answer: {result}")
